CREATE TABLE uav_logs.radar_logs UUID 'c690ac9b-1967-4ff5-9d08-7aa8609490d4' (`device_id` UInt16, `timestamp` DateTime64(3, 'UTC'), `status` LowCardinality(String), `detected` Bool, `drone_type` LowCardinality(String), `accuracy` Float32, `control_state` LowCardinality(Nullable(String)), `latency` Float32, `frequency` Float32 DEFAULT 0.) ENGINE = MergeTree PARTITION BY toYYYYMM(timestamp) ORDER BY (device_id, timestamp) TTL toDateTime(timestamp) + toIntervalMonth(3) SETTINGS index_granularity = 8192